code = """import json
import re
import os
import math

# Initialize variables
clinical_data = []
mutation_data = []

# Load clinical data for female BRCA patients
clinical_file = '/tmp/tmp7n9ebr6z.json'
if os.path.exists(clinical_file):
    with open(clinical_file, 'r') as f:
        clinical_data = json.load(f)
    print('Loaded clinical data: %d records' % len(clinical_data))
else:
    print('Clinical file not found at path: %s' % clinical_file)

# Load CDH1 mutation data
mutation_file = '/tmp/tmpm5w2f8x_.json'
if os.path.exists(mutation_file):
    with open(mutation_file, 'r') as f:
        mutation_data = json.load(f)
    print('Loaded mutation data: %d records' % len(mutation_data))
else:
    print('Mutation file not found at path: %s' % mutation_file)

if not clinical_data or not mutation_data:
    result = {'error': 'Missing required data', 'clinical': len(clinical_data), 'mutations': len(mutation_data)}
else:
    # Process clinical data: extract barcodes and histological types
    patient_histology = {}
    female_brca_count = 0
    
    for record in clinical_data:
        desc = record.get('Patient_description', '')
        hist_type = record.get('histological_type', '')
        
        # Confirm it's a female breast cancer patient
        if 'FEMALE' in desc and ('breast' in desc.lower() or 'BRCA' in desc or 'Breast' in desc):
            female_brca_count += 1
            match = re.search(r'(TCGA-\w{2}-\w{4})', desc)
            if match and hist_type and hist_type not in ['None', '[Not Applicable]', '']:
                barcode = match.group(1)
                patient_histology[barcode] = hist_type.strip()
    
    print('Total female BRCA patients: %d' % female_brca_count)
    print('Patients with valid histology: %d' % len(patient_histology))
    
    # Get set of patients with CDH1 mutations (FILTER=PASS)
    cdh1_patients = set(rec['ParticipantBarcode'] for rec in mutation_data if rec.get('Hugo_Symbol') == 'CDH1')
    print('Total CDH1 mutation patients: %d' % len(cdh1_patients))
    
    # Build contingency table: histological type vs CDH1 mutation status
    contingency_table = {}
    for barcode, hist_type in patient_histology.items():
        if hist_type not in contingency_table:
            contingency_table[hist_type] = [0, 0]  # [has mutation, no mutation]
        
        if barcode in cdh1_patients:
            contingency_table[hist_type][0] += 1
        else:
            contingency_table[hist_type][1] += 1
    
    print('Contingency table before filtering:')
    for hist, counts in contingency_table.items():
        print('  %s: %s' % (hist, counts))
    
    # Filter out histological types with marginal totals <= 10
    filtered_table = {}
    excluded_types = []
    
    for hist_type, counts in contingency_table.items():
        total = sum(counts)
        if total > 10:
            filtered_table[hist_type] = counts
        else:
            excluded_types.append((hist_type, total))
    
    print('\nExcluded %d histological types with <=10 patients:' % len(excluded_types))
    for hist, total in excluded_types:
        print('  %s (n=%d)' % (hist, total))
    
    print('\nFiltered table with %d histological types:' % len(filtered_table))
    for hist, counts in filtered_table.items():
        print('  %s: %s' % (hist, counts))
    
    # Calculate chi-square statistic
    chi_square = 0.0
    degrees_of_freedom = 0
    
    if len(filtered_table) >= 2:
        # Calculate marginal totals
        row_totals = {hist: sum(counts) for hist, counts in filtered_table.items()}
        col_totals = [sum(c[0] for c in filtered_table.values()), sum(c[1] for c in filtered_table.values())]
        grand_total = sum(col_totals)
        
        print('\nMarginal totals:')
        print('  Row totals: %s' % row_totals)
        print('  Column totals: %s' % col_totals)
        print('  Grand total: %d' % grand_total)
        
        if grand_total > 0:
            # Calculate chi-square
            for hist, counts in filtered_table.items():
                for j in range(2):  # j=0: mutated, j=1: not mutated
                    observed = counts[j]
                    expected = (row_totals[hist] * col_totals[j]) / grand_total
                    
                    if expected > 0:
                        contribution = ((observed - expected) ** 2) / expected
                        chi_square += contribution
                        print('  %s, col %d: obs=%d, exp=%.2f, contrib=%.4f' % (hist, j, observed, expected, contribution))
            
            # Degrees of freedom: (rows - 1) * (columns - 1)
            degrees_of_freedom = (len(filtered_table) - 1) * (2 - 1)
            
            print('\nChi-square statistic: %.4f' % chi_square)
            print('Degrees of freedom: %d' % degrees_of_freedom)
        else:
            print('Error: Grand total is 0')
    else:
        print('Not enough categories for chi-square test (need >=2, have %d)' % len(filtered_table))
    
    # Prepare result
    result = {
        'total_female_brca_patients': len(patient_histology),
        'histological_types_original': len(contingency_table),
        'histological_types_analyzed': len(filtered_table),
        'categories_excluded': len(excluded_types),
        'chi_square_statistic': round(chi_square, 4),
        'degrees_of_freedom': degrees_of_freedom,
        'contingency_table': filtered_table,
        'analysis_notes': 'Only histological types with >10 patients included. CDH1 mutations filtered for reliable entries (FILTER=PASS).'
    }

print('\n__RESULT__:', json.dumps(result))"""

